import os
import tarfile


def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        dest = os.path.realpath(os.path.abspath(dest_path))
        os.makedirs(dest, exist_ok=True)

        with tarfile.open(tar_path, 'r:*') as tar:
            members = tar.getmembers()

            for member in members:
                target = os.path.abspath(os.path.join(dest, member.name))

                if target != dest and not target.startswith(dest + os.sep):
                    return False

                if member.isdev():
                    return False

                if member.issym() or member.islnk():
                    link = member.linkname
                    if os.path.isabs(link):
                        link = os.path.join(dest, link.lstrip(os.sep))
                    link_target = os.path.abspath(
                        os.path.join(os.path.dirname(target), link)
                    )
                    if link_target != dest and not link_target.startswith(dest + os.sep):
                        return False

            for member in members:
                tar.extract(member, path=dest)

        return True
    except Exception:
        return False

import ast
import operator

_ALLOWED_BIN_OPS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.FloorDiv: operator.floordiv,
    ast.Mod: operator.mod,
    ast.Pow: operator.pow,
}

_ALLOWED_UNARY_OPS = {
    ast.UAdd: operator.pos,
    ast.USub: operator.neg,
}


def _eval_node(node):
    if isinstance(node, ast.Expression):
        return _eval_node(node.body)
    if isinstance(node, ast.Constant):
        if isinstance(node.value, bool):
            raise ValueError("Boolean literals are not allowed")
        if isinstance(node.value, (int, float)):
            return node.value
        raise ValueError("Only numeric literals are allowed")
    if isinstance(node, ast.BinOp):
        op = _ALLOWED_BIN_OPS.get(type(node.op))
        if op is None:
            raise ValueError("Unsupported binary operator")
        left = _eval_node(node.left)
        right = _eval_node(node.right)
        return op(left, right)
    if isinstance(node, ast.UnaryOp):
        op = _ALLOWED_UNARY_OPS.get(type(node.op))
        if op is None:
            raise ValueError("Unsupported unary operator")
        return op(_eval_node(node.operand))
    raise ValueError("Unsupported expression")


def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if any error occurs.
    '''
    try:
        if not isinstance(expr, str):
            return ''
        tree = ast.parse(expr, mode='eval')
        result = _eval_node(tree)
        return str(result)
    except Exception:
        return ''

