def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    key_map = {
        "lang": "Accept-Language",
        "encoding": "Accept-Encoding",
        "cache": "Cache-Control",
    }

    if not isinstance(info_type, str) or info_type not in key_map:
        return header
    if not isinstance(info_content, str):
        return header
    if any(ch in info_content for ch in ("\r", "\n", "\x00")):
        return header

