from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    try:
        parser = etree.XMLParser(
            resolve_entities=False,
            no_network=True,
            load_dtd=False,
        )
        root = etree.fromstring(xml_data, parser=parser)
    except etree.XMLSyntaxError:
        return None

    matches = root.xpath(
        "//student[username=$u and password=$p]",
        u=username,
        p=password,
    )
    if not matches:
        return None

    student = matches[0]
    info: Dict[str, str] = {}
    for tag in ("username", "name", "citizenship", "age"):
        elem = student.find(tag)
        info[tag] = elem.text if elem is not None and elem.text is not None else ""

    return info

