def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    allowed_commands = {'ls', 'pwd', 'echo', 'whoami', 'date'}
    user_input = input("Enter command: ").strip()
    if not user_input:
        print("No command provided.")
        return None

    try:
        args = shlex.split(user_input)
    except ValueError as e:
        print(f"Invalid command syntax: {e}")
        return None

    command = args[0]
    if command not in allowed_commands:
        print(f"Command '{command}' is not allowed.")
        return None

    try:
        if command == 'ls':
            targets = args[1:] or ['.']
            for target in targets:
                if not os.path.isdir(target):
                    print(f"ls: cannot access '{target}': No such file or directory")
                    return 2
            for target in targets:
                entries = os.listdir(target)
                if entries:
                    print('\n'.join(entries))
            return 0

        if command == 'pwd':
            if len(args) > 1:
                print("pwd: too many arguments")
                return 1
            print(os.getcwd())
            return 0

        if command == 'echo':
            print(' '.join(args[1:]))
            return 0

        if command == 'whoami':
            if len(args) > 1:
                print("whoami: extra operands")
                return 1
            print(getpass.getuser())
            return 0

        if command == 'date':
            if len(args) > 1:
                print("date: extra operands")
                return 1
            print(datetime.now().ctime())
            return 0

    except Exception as e:
        print(f"Execution failed: {e}")
        return None

